operation.add:
if ($this->config->get('module_oc_kit_seo_core_status')) {
	$scf_base = DIR_SYSTEM . 'library/ockit/seo_core/';
	require_once $scf_base . 'Autoloader.php';
	\OcKit\SeoCore\Autoloader::register($scf_base);
	$this->seoCore = new \OcKit\SeoCore\SeoCore($registry);
	$registry->set('seo_core', $this->seoCore);
} elseif ($this->config->get('config_seo_pro')) {
	$this->seo_pro = new SeoPro($registry);
}

//seo_core pagination guard
if (isset($product_total) && $this->config->get('module_oc_kit_seo_core_status')) {
    $scf_guard = new \OcKit\SeoCore\Libs\PaginationGuard($this->config, $this->response, $this->document, $this->registry);
    $scf_page  = (int)($this->request->get['page'] ?? 1);
    $scf_guard->apply($scf_page, (int)$product_total, (int)(isset($limit) ? $limit : 0));
}
//seo_core pagination guard end

//seo_core pagination guard
if (isset($article_total) && $this->config->get('module_oc_kit_seo_core_status')) {
    $scf_guard = new \OcKit\SeoCore\Libs\PaginationGuard($this->config, $this->response, $this->document, $this->registry);
    $scf_page  = (int)($this->request->get['page'] ?? 1);
    $scf_guard->apply($scf_page, (int)$article_total, (int)(isset($limit) ? $limit : 0));
}
//seo_core pagination guard end

//seo_core pagination guard
if (isset($product_total) && $this->config->get('module_oc_kit_seo_core_status')) {
    $scf_guard = new \OcKit\SeoCore\Libs\PaginationGuard($this->config, $this->response, $this->document, $this->registry);
    $scf_page  = (int)($this->request->get['page'] ?? 1);
    $scf_guard->apply($scf_page, (int)$product_total, (int)(isset($limit) ? $limit : 0));
}
//seo_core pagination guard end

// seo_core image meta applier
if ($this->config->get('module_oc_kit_seo_core_status')) {
    $scf_base = DIR_SYSTEM . 'library/ockit/seo_core/';
    if (file_exists($scf_base . 'libs/ProductImageMetaApplier.php')) {
        require_once $scf_base . 'libs/ProductImageMetaApplier.php';
        $scf_applier = new \OcKit\SeoCore\Libs\ProductImageMetaApplier($this->db, $this->config);
        $scf_applier->apply(
            $data,
            (int)$this->request->get['product_id'],
            (int)$this->config->get('config_language_id'),
            (int)$this->config->get('config_store_id')
        );
    }
}
